const d = $input.item.json.body || $input.item.json;
const conditionMap = { 'above': '📈 broke above', 'below': '📉 dropped below', 'percent_change': '⚡ moved' };
const conditionText = conditionMap[d.condition] || d.condition;
const triggerPrice = `$${Number(d.triggerPrice).toFixed(2)}`;
const currentPrice = `$${Number(d.currentPrice).toFixed(2)}`;

return [{
  json: {
    ...d,
    discordMessage: `🔔 **Price Alert Triggered!**\n**${d.symbol}** ${conditionText} ${triggerPrice}\nCurrent Price: **${currentPrice}**\n👤 User: ${d.userId}`,
    slackMessage: `🔔 *Price Alert* — *${d.symbol}* ${conditionText} ${triggerPrice} (now ${currentPrice})`,
    emailSubject: `[Alpha Terminal] 🔔 ${d.symbol} Price Alert — ${conditionText} ${triggerPrice}`,
    emailBody: `<h2>🔔 Price Alert Triggered</h2><p><b>${d.symbol}</b> has ${conditionText} your alert price of <b>${triggerPrice}</b>.</p><p>Current price: <b style="color:#00C805">${currentPrice}</b></p><p>Alert ID: <code>${d.alertId}</code></p><p style="color:#888;font-size:12px">Fired at ${new Date().toLocaleString()}</p>`
  }
}];
